// OpenAI_患者_訪問人数 の結果を最終確定値にする安全網
var raw = String($runner.getModuleResult("OpenAI_患者_訪問人数") || "").trim();

// 1〜10 のみ許可（それ以外は NO_RESULT）
var m = raw.match(/^(10|[1-9])$/);
$runner.setResult(m ? m[1] : "NO_RESULT");

