params.script:
var ward = String($runner.getModuleResult("OpenAI_患者_病棟_呼び出し") || "").trim();

if (ward === "わからない") {
  $runner.setResult("わからない");
  return;
}

$runner.setResult(ward + "_呼び出し");

var r = $runner.getModuleResult("入力_患者_電話番号_聴取");

// --- データのクレンジング ---
// 数字以外の文字（ハイフン「-」、スペース、括弧など）をすべて除去
var d = r ? String(r).replace(/[^0-9]/g, "") : ""; 

var res = "";

// --- 電話番号のバリデーション論理 ---

// 1. 携帯電話・IP電話: 050, 060, 070, 080, 090 で始まる11桁
var mobilePattern = /^0(50|60|70|80|90)\d{8}$/;

// 2. 固定電話: 050-090以外で始まり、10桁または11桁
var fixedPattern = /^0(?!(50|60|70|80|90))\d{9,10}$/;

// --- 判定処理 ---
if (mobilePattern.test(d) || fixedPattern.test(d)) {
    // バリデーション成功
    res = "VALID";
} else {
    // バリデーション失敗
    res = "INVALID";
}

// 結果をセット（後続のモジュールで #data# として使用）
$runner.setResult(res);

