params.script:
var r = $runner.getModuleResult("入力_患者_電話番号_聴取");
// 数字以外の記号（ハイフンなど）をすべて除去
var d = r ? String(r).replace(/[^0-9]/g, "") : ""; 
var res = "";

// 11桁（携帯・IP電話: 050, 070, 080, 090）
var mobilePattern = /^0(50|60|70|80|90)\d{8}$/;
// 10桁（固定電話）
var fixedPattern = /^0(?!(50|60|70|80|90))\d{9}$/;

// .test() thường chạy ổn, nhưng nếu không được hãy dùng .match()
if (mobilePattern.test(d) || fixedPattern.test(d)) {
    var m = ["ぜろ", "いち", "にい", "さん", "よん", "ごお", "ろく", "なな", "はち", "きゅう"];
    var ssml = "<speak>";
    
    for (var i = 0; i < d.length; i++) {
        var n = parseInt(d.charAt(i), 10);
        // Biến d.charAt(i) lấy trực tiếp ký tự
        var digit = d.charAt(i);
        ssml += "<sub alias='" + m[n] + "'>" + digit + "</sub>";

        // --- Brekeke compatible logic ---
        if (d.length == 11) {
            if (i == 2 || i == 6) {
                ssml += " \u306E <break time='300ms'/> ";
            }
        } else if (d.length == 10) {
            // Dùng substring thay cho indexOf để an toàn hơn trên engine cũ
            var prefix2 = d.substring(0, 2); 
            if (prefix2 == "03" || prefix2 == "06") {
                if (i == 1 || i == 5) {
                    ssml += " \u306E <break time='300ms'/> ";
                }
            } else {
                if (i == 2 || i == 5) {
                    ssml += " \u306E <break time='300ms'/> ";
                }
            }
        }
    }
    // Đã xóa chữ INVALID bị thừa ở đây
    ssml += "</speak>";
    res = ssml;
} else {
    res = "INVALID";
}

$runner.setResult(res);

var ward = String($runner.getModuleResult("OpenAI_患者_病棟") || "").trim();

if (ward === "わからない") {
  $runner.setResult("わからない");
  return;
}

$runner.setResult(ward + "_面会");
